/** Group-chat speaker selection & message shaping (plan §3). Pure, so it's
 * unit-testable without the DB/store layer. */

import type { PromptMessage } from "../prompt/promptBuilder";
import { foldForSearch } from "./searchSnippet";

export interface SpeakerCandidate {
  id: string;
  name: string;
  position: number;
}

/** Picks the next auto-mode speaker (plan §1/§3):
 * 1. If exactly one or more members are mentioned by name (fold-insensitive
 *    substring) in `lastUserText`, the one mentioned *last* in the text wins.
 * 2. Otherwise least-recently-spoken: members absent from `recentSpeakerIds`
 *    entirely go first (by `position`); among the rest, the one whose last
 *    occurrence in `recentSpeakerIds` has the smallest index (spoke longest
 *    ago) wins.
 * Returns null for an empty member list. */
export function pickNextSpeaker(
  members: SpeakerCandidate[],
  lastUserText: string,
  recentSpeakerIds: string[],
): string | null {
  if (members.length === 0) return null;
  if (members.length === 1) return members[0].id;

  const folded = foldForSearch(lastUserText);
  let mentionedId: string | null = null;
  let mentionedLastIdx = -1;
  for (const member of members) {
    const name = foldForSearch(member.name).trim();
    if (!name) continue;
    const idx = folded.lastIndexOf(name);
    if (idx > mentionedLastIdx) {
      mentionedLastIdx = idx;
      mentionedId = member.id;
    }
  }
  if (mentionedId) return mentionedId;

  const neverSpoken = members.filter((m) => !recentSpeakerIds.includes(m.id));
  if (neverSpoken.length > 0) {
    return [...neverSpoken].sort((a, b) => a.position - b.position)[0].id;
  }

  // Least-recently-spoken: smallest index of the *last* occurrence in
  // recentSpeakerIds (oldest -> newest) means "spoke longest ago".
  let best: SpeakerCandidate | null = null;
  let bestLastIdx = Number.POSITIVE_INFINITY;
  for (const member of members) {
    const lastIdx = recentSpeakerIds.lastIndexOf(member.id);
    if (lastIdx < bestLastIdx) {
      bestLastIdx = lastIdx;
      best = member;
    }
  }
  return best ? best.id : members[0].id;
}

/** Strips a leading `Name:` or `**Name:**` prefix (case/diacritics
 * insensitive, matched via `foldForSearch`), including the optional space
 * after the colon. Leaves occurrences elsewhere in the text untouched. */
export function stripSpeakerPrefix(text: string, name: string): string {
  const foldedName = foldForSearch(name).trim();
  if (!foldedName) return text;

  const tryStrip = (prefixPattern: RegExp): string | null => {
    const match = prefixPattern.exec(text);
    if (!match) return null;
    const candidateName = match[1];
    if (foldForSearch(candidateName).trim() !== foldedName) return null;
    return text.slice(match[0].length);
  };

  // Bold form: **Name:** (with optional trailing space)
  const bold = tryStrip(/^\*\*([^*:\n]+):\*\*[ \t]?/);
  if (bold !== null) return bold;

  // Plain form: Name: (with optional trailing space)
  const plain = tryStrip(/^([^:\n*]+):[ \t]?/);
  if (plain !== null) return plain;

  return text;
}

/** Merges adjacent messages of the same role by joining their content with
 * "\n\n" — required before sending to providers with strict role
 * alternation (e.g. Claude), since group chats can produce back-to-back
 * assistant turns (plan: mergeConsecutiveRoles). */
export function mergeConsecutiveRoles(messages: PromptMessage[]): PromptMessage[] {
  const out: PromptMessage[] = [];
  for (const msg of messages) {
    const last = out[out.length - 1];
    if (last && last.role === msg.role) {
      last.content = `${last.content}\n\n${msg.content}`;
    } else {
      out.push({ ...msg });
    }
  }
  return out;
}

import { describe, expect, it } from "vitest";

import { mergeConsecutiveRoles, pickNextSpeaker, stripSpeakerPrefix, type SpeakerCandidate } from "./groupSpeaker";
import type { PromptMessage } from "../prompt/promptBuilder";

const MEMBERS: SpeakerCandidate[] = [
  { id: "a", name: "Anna", position: 0 },
  { id: "b", name: "Věž", position: 1 },
  { id: "c", name: "Kai", position: 2 },
];

describe("pickNextSpeaker", () => {
  it("returns null for an empty member list", () => {
    expect(pickNextSpeaker([], "hello", [])).toBeNull();
  });

  it("returns the only member for a single-member list, ignoring text/history", () => {
    const single: SpeakerCandidate[] = [{ id: "a", name: "Anna", position: 0 }];
    expect(pickNextSpeaker(single, "", [])).toBe("a");
  });

  it("matches a name mentioned without diacritics ('vez' -> 'Věž')", () => {
    expect(pickNextSpeaker(MEMBERS, "rekni to vez", [])).toBe("b");
  });

  it("picks the last-mentioned member when several are named in the text", () => {
    const text = "Anna a Kai si povidali, pak prisla Vez.";
    expect(pickNextSpeaker(MEMBERS, text, [])).toBe("b");
  });

  it("falls back to round-robin on the longest-silent member when no name is mentioned", () => {
    // a and b have spoken recently (oldest -> newest); c never spoke.
    const recent = ["a", "b", "a"];
    expect(pickNextSpeaker(MEMBERS, "no names here", recent)).toBe("c");
  });

  it("prefers never-spoken members by position when several never spoke", () => {
    const recent = ["a"]; // b and c never spoke; b has lower position
    expect(pickNextSpeaker(MEMBERS, "", recent)).toBe("b");
  });

  it("picks the member who spoke longest ago when everyone has spoken", () => {
    const recent = ["c", "a", "b", "a"]; // last occurrence indices: c=0, a=3, b=2
    expect(pickNextSpeaker(MEMBERS, "", recent)).toBe("c");
  });

  it("handles empty text by falling back to round-robin", () => {
    expect(pickNextSpeaker(MEMBERS, "", [])).toBe("a");
  });
});

describe("stripSpeakerPrefix", () => {
  it("strips a plain 'Name:' prefix", () => {
    expect(stripSpeakerPrefix("Anna: Hello there.", "Anna")).toBe("Hello there.");
  });

  it("strips a bold '**Name:**' prefix", () => {
    expect(stripSpeakerPrefix("**Anna:** Hello there.", "Anna")).toBe("Hello there.");
  });

  it("is case/diacritics insensitive when matching the prefix", () => {
    expect(stripSpeakerPrefix("VEZ: Ahoj.", "Věž")).toBe("Ahoj.");
  });

  it("does not touch an occurrence of the name in the middle of the text", () => {
    const text = "He said hello, Anna: that was odd.";
    expect(stripSpeakerPrefix(text, "Anna")).toBe(text);
  });

  it("is a no-op when the prefix belongs to a different name", () => {
    const text = "Kai: Hello there.";
    expect(stripSpeakerPrefix(text, "Anna")).toBe(text);
  });

  it("is a no-op on text with no prefix at all", () => {
    const text = "Just a plain sentence.";
    expect(stripSpeakerPrefix(text, "Anna")).toBe(text);
  });
});

describe("mergeConsecutiveRoles", () => {
  it("merges adjacent same-role messages by joining content with \\n\\n", () => {
    const input: PromptMessage[] = [
      { role: "system", content: "sys" },
      { role: "assistant", content: "Anna: Hi." },
      { role: "assistant", content: "Kai: Yo." },
      { role: "user", content: "Hey both." },
    ];
    expect(mergeConsecutiveRoles(input)).toEqual([
      { role: "system", content: "sys" },
      { role: "assistant", content: "Anna: Hi.\n\nKai: Yo." },
      { role: "user", content: "Hey both." },
    ]);
  });

  it("leaves already-alternating messages untouched", () => {
    const input: PromptMessage[] = [
      { role: "user", content: "u1" },
      { role: "assistant", content: "a1" },
      { role: "user", content: "u2" },
    ];
    expect(mergeConsecutiveRoles(input)).toEqual(input);
  });

  it("handles an empty list", () => {
    expect(mergeConsecutiveRoles([])).toEqual([]);
  });

  it("does not mutate the input array's message objects", () => {
    const input: PromptMessage[] = [
      { role: "assistant", content: "a1" },
      { role: "assistant", content: "a2" },
    ];
    const out = mergeConsecutiveRoles(input);
    expect(input[0].content).toBe("a1");
    expect(out[0].content).toBe("a1\n\na2");
  });
});

/** Case- and diacritics-insensitive search helpers ("Věž" matches "vez").
 * Pure, so they're unit-testable. */

function foldChar(ch: string): string {
  return ch.normalize("NFD").replace(/[\u0300-\u036f]/g, "").toLowerCase();
}

/** Folds a whole string for matching ("Věž a 😀" → "vez a 😀"). */
export function foldForSearch(text: string): string {
  return [...text].map(foldChar).join("");
}

/** Index (in code points) of the first folded occurrence of `term` inside
 * `contentChars`, or -1. Walks per code point so emoji and other multi-unit
 * characters don't skew positions. */
function foldedIndexOf(contentChars: string[], term: string): number {
  const target = foldForSearch(term);
  if (!target) return -1;
  for (let i = 0; i < contentChars.length; i++) {
    let acc = "";
    for (let j = i; j < contentChars.length && acc.length < target.length; j++) {
      acc += foldChar(contentChars[j]);
    }
    if (acc.startsWith(target)) return i;
  }
  return -1;
}

/** Builds a short snippet around the first occurrence of `term` in
 * `content`, matching without regard to case or diacritics — used by the
 * chat-list search results. */
export function searchSnippet(content: string, term: string, radius = 60): string {
  const chars = [...content];
  const idx = foldedIndexOf(chars, term);
  if (idx === -1) {
    return chars.slice(0, radius * 2).join("") + (chars.length > radius * 2 ? "…" : "");
  }
  const start = Math.max(0, idx - radius);
  const end = Math.min(chars.length, idx + [...term].length + radius);
  return (
    (start > 0 ? "…" : "") + chars.slice(start, end).join("") + (end < chars.length ? "…" : "")
  );
}

/** Lorebook activation scan (plan §6.4). Pure logic, no DB/Tauri
 * dependency on purpose — this module is unit-tested with vitest without
 * booting the Tauri runtime. Callers (chatStore / systemPrompt glue) load
 * entries via `db/repositories/lorebooksRepo.ts` and pass plain data in. */

export interface LoreEntryLike {
  id: string;
  keys: string[];
  secondaryKeys: string[];
  content: string;
  priority: number;
  alwaysOn: boolean;
  caseSensitive: boolean;
  enabled: boolean;
}

export interface ActivationOptions {
  /** How many of the most recent messages to scan for keys. Default 4
   * (`lore_scan_depth` setting). */
  scanDepth?: number;
  /** Token budget for activated entry content. Default 800
   * (`lore_token_budget` setting). */
  tokenBudget?: number;
}

export const DEFAULT_SCAN_DEPTH = 4;
export const DEFAULT_TOKEN_BUDGET = 800;

/** Same rough token estimate used across the app: ~4 chars/token. */
export function estimateTokens(text: string): number {
  return Math.ceil(text.length / 4);
}

/** Joins the text of the last `scanDepth` messages (oldest first, in the
 * order given) into a single haystack for key matching. */
export function buildScanText(recentMessages: string[], scanDepth: number = DEFAULT_SCAN_DEPTH): string {
  return recentMessages.slice(-scanDepth).join("\n");
}

/** A single key matches when it's a non-empty substring of the scan text,
 * case-sensitively or not depending on the entry's setting. */
function keyMatches(key: string, scanText: string, caseSensitive: boolean): boolean {
  const needle = key.trim();
  if (!needle) return false;
  if (caseSensitive) return scanText.includes(needle);
  return scanText.toLowerCase().includes(needle.toLowerCase());
}

/** Whether an entry is activated by the given scan text. Disabled entries
 * are never active. `always_on` entries are always active (once enabled).
 * Otherwise any of `keys` matching as a substring activates the entry —
 * `secondary_keys` are not required by this simple scan (selective/AND
 * matching is out of scope for M4, keys-only OR matching per plan §6.4). */
export function isEntryActive(entry: LoreEntryLike, scanText: string): boolean {
  if (!entry.enabled) return false;
  if (entry.alwaysOn) return true;
  return entry.keys.some((k) => keyMatches(k, scanText, entry.caseSensitive));
}

/** Full activation scan: builds the scan text from the last `scanDepth`
 * messages, filters to entries that activate, sorts by priority descending,
 * and takes as many (in that order) as fit within `tokenBudget`. Stops at
 * the first entry that would overflow the budget rather than skipping it
 * for a smaller later one, so higher-priority content always wins. */
export function selectActiveEntries(
  entries: LoreEntryLike[],
  recentMessages: string[],
  options: ActivationOptions = {},
): LoreEntryLike[] {
  const scanDepth = options.scanDepth ?? DEFAULT_SCAN_DEPTH;
  const tokenBudget = options.tokenBudget ?? DEFAULT_TOKEN_BUDGET;
  const scanText = buildScanText(recentMessages, scanDepth);

  const active = entries.filter((e) => isEntryActive(e, scanText));
  active.sort((a, b) => b.priority - a.priority);

  const selected: LoreEntryLike[] = [];
  let used = 0;
  for (const entry of active) {
    const cost = estimateTokens(entry.content);
    if (used + cost > tokenBudget) break;
    selected.push(entry);
    used += cost;
  }
  return selected;
}

import { describe, expect, it } from "vitest";

import {
  buildScanText,
  estimateTokens,
  isEntryActive,
  selectActiveEntries,
  type LoreEntryLike,
} from "./activation";

function entry(partial: Partial<LoreEntryLike>): LoreEntryLike {
  return {
    id: partial.id ?? "e1",
    keys: partial.keys ?? [],
    secondaryKeys: partial.secondaryKeys ?? [],
    content: partial.content ?? "",
    priority: partial.priority ?? 100,
    alwaysOn: partial.alwaysOn ?? false,
    caseSensitive: partial.caseSensitive ?? false,
    enabled: partial.enabled ?? true,
  };
}

describe("estimateTokens", () => {
  it("rounds up chars/4", () => {
    expect(estimateTokens("")).toBe(0);
    expect(estimateTokens("abcd")).toBe(1);
    expect(estimateTokens("abcde")).toBe(2);
    expect(estimateTokens("a".repeat(800))).toBe(200);
  });
});

describe("buildScanText", () => {
  it("keeps only the last scanDepth messages, in order", () => {
    const messages = ["one", "two", "three", "four", "five"];
    expect(buildScanText(messages, 2)).toBe("four\nfive");
    expect(buildScanText(messages, 100)).toBe(messages.join("\n"));
  });

  it("defaults to the last 4 messages", () => {
    const messages = ["a", "b", "c", "d", "e"];
    expect(buildScanText(messages)).toBe("b\nc\nd\ne");
  });
});

describe("isEntryActive", () => {
  it("is never active when disabled, even if always_on", () => {
    const e = entry({ alwaysOn: true, enabled: false });
    expect(isEntryActive(e, "anything")).toBe(false);
  });

  it("is always active when always_on and enabled, regardless of keys", () => {
    const e = entry({ alwaysOn: true, keys: [] });
    expect(isEntryActive(e, "totally unrelated text")).toBe(true);
  });

  it("activates on a case-insensitive substring match by default", () => {
    const e = entry({ keys: ["Dragon"] });
    expect(isEntryActive(e, "a dragon appears")).toBe(true);
    expect(isEntryActive(e, "a DRAGON appears")).toBe(true);
    expect(isEntryActive(e, "no reptiles here")).toBe(false);
  });

  it("respects case_sensitive when set", () => {
    const e = entry({ keys: ["Dragon"], caseSensitive: true });
    expect(isEntryActive(e, "a Dragon appears")).toBe(true);
    expect(isEntryActive(e, "a dragon appears")).toBe(false);
  });

  it("activates if ANY key matches", () => {
    const e = entry({ keys: ["castle", "throne"] });
    expect(isEntryActive(e, "the throne room")).toBe(true);
    expect(isEntryActive(e, "nothing relevant")).toBe(false);
  });

  it("ignores blank keys", () => {
    const e = entry({ keys: ["", "  "] });
    expect(isEntryActive(e, "some text")).toBe(false);
  });
});

describe("selectActiveEntries", () => {
  it("only includes entries whose keys appear in the scanned recent messages", () => {
    const entries = [
      entry({ id: "castle", keys: ["castle"] }),
      entry({ id: "dragon", keys: ["dragon"] }),
    ];
    const messages = ["We approach the castle gates."];
    const selected = selectActiveEntries(entries, messages);
    expect(selected.map((e) => e.id)).toEqual(["castle"]);
  });

  it("only scans the last `scanDepth` messages", () => {
    const entries = [entry({ id: "old", keys: ["griffin"] })];
    // "griffin" only appears in a message older than the scan window.
    const messages = ["griffin sighted", "b", "c", "d", "e"];
    expect(selectActiveEntries(entries, messages, { scanDepth: 4 })).toHaveLength(0);
    expect(selectActiveEntries(entries, messages, { scanDepth: 5 })).toHaveLength(1);
  });

  it("sorts activated entries by priority descending", () => {
    const entries = [
      entry({ id: "low", keys: ["x"], priority: 1 }),
      entry({ id: "high", keys: ["x"], priority: 50 }),
      entry({ id: "mid", keys: ["x"], priority: 10 }),
    ];
    const selected = selectActiveEntries(entries, ["x"]);
    expect(selected.map((e) => e.id)).toEqual(["high", "mid", "low"]);
  });

  it("always_on entries activate without any key mention", () => {
    const entries = [entry({ id: "world-rule", alwaysOn: true, keys: [] })];
    const selected = selectActiveEntries(entries, ["completely unrelated chat"]);
    expect(selected.map((e) => e.id)).toEqual(["world-rule"]);
  });

  it("stops adding entries once the token budget would be exceeded", () => {
    // Each entry's content is 40 chars -> 10 tokens (Math.ceil(40/4)).
    const content40 = "x".repeat(40);
    const entries = [
      entry({ id: "a", keys: ["x"], priority: 3, content: content40 }),
      entry({ id: "b", keys: ["x"], priority: 2, content: content40 }),
      entry({ id: "c", keys: ["x"], priority: 1, content: content40 }),
    ];
    // Budget of 25 tokens fits entry "a" (10) + "b" (10) = 20, but not "c" (would be 30).
    const selected = selectActiveEntries(entries, ["x"], { tokenBudget: 25 });
    expect(selected.map((e) => e.id)).toEqual(["a", "b"]);
  });

  it("excludes disabled entries even if their keys match", () => {
    const entries = [entry({ id: "off", keys: ["x"], enabled: false })];
    expect(selectActiveEntries(entries, ["x"])).toHaveLength(0);
  });
});

/** SillyTavern World Info JSON <-> lore_entries field mapping (plan §6.4).
 * Pure mapping logic, no DB/Tauri dependency so it's unit-testable without
 * the Tauri runtime — file picking/reading and DB writes are wired up in
 * `db/repositories/lorebooksRepo.ts` and the lorebooks UI. */

/** One entry inside a SillyTavern World Info JSON file's `entries` map
 * (keyed by uid, an arbitrary string/number). Only the fields this app
 * models are typed here; unknown extra fields are ignored on import and
 * not preserved on export (matches the plan's mapping table exactly). */
export interface WorldInfoEntryJson {
  key?: string[];
  keysecondary?: string[];
  content?: string;
  comment?: string;
  constant?: boolean;
  order?: number;
  disable?: boolean;
  case_sensitive?: boolean;
}

export interface WorldInfoFile {
  entries: Record<string, WorldInfoEntryJson>;
}

/** DB-shape-independent view of a lore entry's editable fields — matches
 * `lore_entries` columns minus `id`/`lorebook_id`/`created_at`. */
export interface LoreEntryFields {
  keys: string[];
  secondaryKeys: string[];
  content: string;
  comment: string;
  priority: number;
  alwaysOn: boolean;
  caseSensitive: boolean;
  enabled: boolean;
}

/** Parses raw World Info JSON text into entry field lists ready to insert
 * as `lore_entries`. Throws if the JSON doesn't have an `entries` object. */
export function parseWorldInfoJson(text: string): LoreEntryFields[] {
  const parsed = JSON.parse(text) as Partial<WorldInfoFile>;
  if (!parsed.entries || typeof parsed.entries !== "object") {
    throw new Error("World Info soubor neobsahuje pole 'entries'.");
  }
  return worldInfoToEntries(parsed as WorldInfoFile);
}

export function worldInfoToEntries(wi: WorldInfoFile): LoreEntryFields[] {
  return Object.values(wi.entries ?? {}).map((e) => ({
    keys: Array.isArray(e.key) ? e.key : [],
    secondaryKeys: Array.isArray(e.keysecondary) ? e.keysecondary : [],
    content: e.content ?? "",
    comment: e.comment ?? "",
    priority: e.order ?? 100,
    alwaysOn: e.constant === true,
    caseSensitive: e.case_sensitive === true,
    enabled: e.disable !== true,
  }));
}

/** Mirrors `worldInfoToEntries`: builds a World Info JSON object from a
 * list of lore entries, suitable for `JSON.stringify` + writing to disk.
 * Entry keys in the `entries` map are stable stringified indices — order
 * is preserved by the caller's array order. */
export function entriesToWorldInfo(entries: LoreEntryFields[]): WorldInfoFile {
  const result: Record<string, WorldInfoEntryJson> = {};
  entries.forEach((entry, index) => {
    result[String(index)] = {
      key: entry.keys,
      keysecondary: entry.secondaryKeys,
      content: entry.content,
      comment: entry.comment,
      constant: entry.alwaysOn,
      order: entry.priority,
      disable: !entry.enabled,
      case_sensitive: entry.caseSensitive,
    };
  });
  return { entries: result };
}

export function stringifyWorldInfo(entries: LoreEntryFields[]): string {
  return JSON.stringify(entriesToWorldInfo(entries), null, 2);
}

import { describe, expect, it } from "vitest";

import worldInfoSampleFixture from "./__fixtures__/worldInfoSample.json";
import {
  entriesToWorldInfo,
  parseWorldInfoJson,
  worldInfoToEntries,
  type LoreEntryFields,
  type WorldInfoFile,
} from "./worldInfoImport";

/** A realistic-shaped SillyTavern World Info export fixture — the same
 * field names/shape as a real "Ashford Keep.json" world book: an
 * `entries` map keyed by uid, mixing constant (always-on), keyed, and
 * disabled entries with non-default priorities and case sensitivity. */
const FIXTURE: WorldInfoFile = {
  entries: {
    "0": {
      key: ["Ashford", "the keep"],
      keysecondary: ["siege"],
      content: "Ashford Keep has stood for three centuries and never fallen to siege.",
      comment: "Setting: Ashford Keep",
      constant: false,
      order: 100,
      disable: false,
      case_sensitive: false,
    },
    "1": {
      key: [],
      keysecondary: [],
      content: "The realm's calendar uses a 10-month year; magic is rare and feared.",
      comment: "World rules",
      constant: true,
      order: 200,
      disable: false,
      case_sensitive: false,
    },
    "2": {
      key: ["Captain Vane"],
      content: "Captain Vane secretly serves the rival house of Ardenne.",
      comment: "NPC secret",
      constant: false,
      order: 50,
      disable: true,
      case_sensitive: true,
    },
  },
};

describe("worldInfoToEntries", () => {
  it("maps every World Info field to its lore_entries counterpart per the plan's mapping table", () => {
    const entries = worldInfoToEntries(FIXTURE);
    expect(entries).toHaveLength(3);

    const ashford = entries.find((e) => e.comment === "Setting: Ashford Keep")!;
    expect(ashford.keys).toEqual(["Ashford", "the keep"]);
    expect(ashford.secondaryKeys).toEqual(["siege"]);
    expect(ashford.content).toBe(
      "Ashford Keep has stood for three centuries and never fallen to siege.",
    );
    expect(ashford.priority).toBe(100);
    expect(ashford.alwaysOn).toBe(false);
    expect(ashford.caseSensitive).toBe(false);
    expect(ashford.enabled).toBe(true); // disable: false -> enabled: true

    const worldRules = entries.find((e) => e.comment === "World rules")!;
    expect(worldRules.alwaysOn).toBe(true); // constant: true -> always_on

    const secret = entries.find((e) => e.comment === "NPC secret")!;
    expect(secret.enabled).toBe(false); // disable: true -> !enabled
    expect(secret.caseSensitive).toBe(true);
  });

  it("defaults missing optional fields sensibly", () => {
    const [entry] = worldInfoToEntries({ entries: { "0": {} } });
    expect(entry.keys).toEqual([]);
    expect(entry.secondaryKeys).toEqual([]);
    expect(entry.content).toBe("");
    expect(entry.comment).toBe("");
    expect(entry.priority).toBe(100);
    expect(entry.alwaysOn).toBe(false);
    expect(entry.caseSensitive).toBe(false);
    expect(entry.enabled).toBe(true);
  });
});

describe("parseWorldInfoJson", () => {
  it("parses a real-shaped World Info JSON file's text", () => {
    const entries = parseWorldInfoJson(JSON.stringify(FIXTURE));
    expect(entries).toHaveLength(3);
  });

  it("throws on JSON without an `entries` object", () => {
    expect(() => parseWorldInfoJson(JSON.stringify({ foo: "bar" }))).toThrow();
  });

  it("imports the on-disk World Info sample fixture (`__fixtures__/worldInfoSample.json`) — this stands in for M4's 'import a real World Info JSON' acceptance check", () => {
    const entries = parseWorldInfoJson(JSON.stringify(worldInfoSampleFixture));
    expect(entries).toHaveLength(3);
