/** Cheap Czech noun inflection expansion for lorebook keywords.
 *
 * Appends common case/number suffixes to each key so that the substring
 * scanner in `activation.ts` can match inflected forms (e.g. key "meč"
 * also matches "mečem", "meče", "meči").  The expansion is intentionally
 * aggressive — false positives are harmless and are preferred over
 * missed activations. */

/** Suffixes drawn from all Czech nominal paradigms (masculine animate /
 * inanimate, feminine, neuter).  Appending them to a consonant-final stem
 * produces many valid surface forms; vowel-final keys are also stemmed
 * heuristically before suffixing. */
const INFLECTION_SUFFIXES = [
  "e", "i", "ovi", "a", "y", "ů", "ům", "ech", "ích", "em", "ové",
  "u", "ou", "ách", "ám", "ami", "atech", "at", "atům", "aty",
];

const MIN_KEY_LENGTH = 3;
const MAX_EXPANDED = 100;

/** Vowel endings that are likely nominative-singular suffixes rather
 * than part of the stem.  Stripping them before suffixing often yields
 * a usable stem (e.g. "žena" → "žen" + "y" = "ženy"). */
const NOMINATIVE_VOWEL_RE = /[aeoíýáéůě]$/u;

/**
 * Expand a list of lorebook keys into the original keys plus common
 * Czech inflected forms.  Multi-word keys only inflect the last word
 * (the head noun).  Very short keys (< 3 chars) are left as-is.
 *
 * The returned array is deduplicated and limited to at most
 * `MAX_EXPANDED` entries for practical use in the scanner.
 */
export function expandKeys(keys: string[]): string[] {
  const results = new Set<string>();

  for (const rawKey of keys) {
    const key = rawKey.trim();
    if (!key) continue;

    // Always preserve the original key.
    results.add(key);

    if (key.length < MIN_KEY_LENGTH) continue;

    // Multi-word phrase → only inflect the last word (the head noun).
    const words = key.split(/\s+/);
    const lastWord = words[words.length - 1];
    const prefix = words.length > 1 ? words.slice(0, -1).join(" ") + " " : "";

    if (lastWord.length < MIN_KEY_LENGTH) continue;

    const stems = new Set<string>();
    stems.add(lastWord); // consonant-final stem (e.g. "meč")

    // Try stripping a nominative vowel ending for vowel-final keys.
    const trimmed = lastWord.replace(NOMINATIVE_VOWEL_RE, "");
    if (trimmed && trimmed.length >= 2 && trimmed !== lastWord) {
      stems.add(trimmed);
    }

    for (const stem of stems) {
      for (const suffix of INFLECTION_SUFFIXES) {
        results.add(prefix + stem + suffix);
      }
    }
  }

  return [...results].slice(0, MAX_EXPANDED);
}

import { describe, expect, it } from "vitest";

import { expandKeys } from "./stemming";

describe("expandKeys", () => {
  it("includes the original key in the result", () => {
    const result = expandKeys(["meč"]);
    expect(result).toContain("meč");
  });

  it("generates common inflected forms for a consonant-final masculine noun", () => {
    const result = expandKeys(["meč"]);
    // Some expected forms (not exhaustive — just sanity).
    expect(result).toContain("meče");
    expect(result).toContain("meči");
    expect(result).toContain("mečem");
    expect(result).toContain("mečů");
    expect(result).toContain("mečům");
  });

  it("generates forms for a vowel-final feminine noun by stripping and suffixing", () => {
    const result = expandKeys(["žena"]);
    // Stem "žen" + suffixes should give:
    expect(result).toContain("ženy");
    expect(result).toContain("ženě"); // Wait, "ě" is not in suffixes... hmm
    // Actually with our suffixes: "žen" + "y" = "ženy", "žen" + "e" = "žene", etc.
    expect(result).toContain("ženy");
    // Also forms from full word: "žena" + "y" = "ženay" (nonsense but harmless)
    expect(result).toContain("ženay");
    // The original key.
    expect(result).toContain("žena");
  });

  it("handles multi-word keys — only stems the last word", () => {
    const result = expandKeys(["černý meč"]);
    expect(result).toContain("černý meč"); // original
    expect(result).toContain("černý meče");
    expect(result).toContain("černý mečem");
    // First word "černý" should NOT be stemmed — no "čern meč" etc.
    expect(result).not.toContain("čern meč");
  });

  it("skips keys shorter than 3 characters", () => {
    const result = expandKeys(["a", "ab", "abc"]);
    expect(result).toContain("a");
    expect(result).toContain("ab");
    expect(result).toContain("abc");
    // "abc" gets expanded, "a" and "ab" don't.
    const expanded = result.filter((k) => k !== "a" && k !== "ab" && k !== "abc");
    // All expanded forms should start with "abc"
    for (const form of expanded) {
      expect(form.startsWith("abc")).toBe(true);
    }
  });

  it("deduplicates identical forms", () => {
    const result = expandKeys(["meč", "meč"]);
    const count = result.filter((k) => k === "meč").length;
    expect(count).toBe(1);
  });

  it("filters out blank keys", () => {
    const result = expandKeys(["", "  ", "meč"]);
    expect(result).not.toContain("");
    expect(result).not.toContain("  ");
    expect(result).toContain("meč");
  });

  it("caps the total at 100 per entry", () => {
    // Each key with 2 stems × 20 suffixes = ~40 forms; 3 keys → ~120 but capped.
    const result = expandKeys(["meč", "drak", "hrad"]);
    expect(result.length).toBeLessThanOrEqual(100);
  });

  it("is pure — returns a new array without mutating input", () => {
    const input = ["meč"];
    const result = expandKeys(input);
    expect(result).not.toBe(input);
    expect(input).toEqual(["meč"]);
  });

  it("handles an empty key list gracefully", () => {
    expect(expandKeys([])).toEqual([]);
  });
});

/** SillyTavern World Info JSON <-> lore_entries field mapping (plan §6.4).
 * Pure mapping logic, no DB/Tauri dependency so it's unit-testable without
 * the Tauri runtime — file picking/reading and DB writes are wired up in
 * `db/repositories/lorebooksRepo.ts` and the lorebooks UI. */

import { expandKeys } from "./stemming";

/** One entry inside a SillyTavern World Info JSON file's `entries` map
 * (keyed by uid, an arbitrary string/number). Only the fields this app
 * models are typed here; unknown extra fields are ignored on import and
 * not preserved on export (matches the plan's mapping table exactly). */
export interface WorldInfoEntryJson {
  key?: string[];
  keysecondary?: string[];
  content?: string;
  comment?: string;
  constant?: boolean;
  order?: number;
  disable?: boolean;
  case_sensitive?: boolean;
}

export interface WorldInfoFile {
  entries: Record<string, WorldInfoEntryJson>;
}

/** DB-shape-independent view of a lore entry's editable fields — matches
 * `lore_entries` columns minus `id`/`lorebook_id`/`created_at`. */
export interface LoreEntryFields {
  keys: string[];
  secondaryKeys: string[];
  content: string;
  comment: string;
  priority: number;
  alwaysOn: boolean;
  caseSensitive: boolean;
  enabled: boolean;
}

/** Parses raw World Info JSON text into entry field lists ready to insert
 * as `lore_entries`. Throws if the JSON doesn't have an `entries` object. */
export function parseWorldInfoJson(text: string): LoreEntryFields[] {
  const parsed = JSON.parse(text) as Partial<WorldInfoFile>;
  if (!parsed.entries || typeof parsed.entries !== "object") {
    throw new Error("World Info soubor neobsahuje pole 'entries'.");
  }
  return worldInfoToEntries(parsed as WorldInfoFile);
}

export function worldInfoToEntries(wi: WorldInfoFile): LoreEntryFields[] {
  return Object.values(wi.entries ?? {}).map((e) => {
    const keys = Array.isArray(e.key) ? e.key : [];
    const secondaryKeys = Array.isArray(e.keysecondary) ? e.keysecondary : [];
    // Merge user-supplied secondary keys with auto-expanded primary keys.
    const mergedSecondary = [...new Set([...secondaryKeys, ...expandKeys(keys)])];
    return {
      keys,
      secondaryKeys: mergedSecondary,
      content: e.content ?? "",
      comment: e.comment ?? "",
      priority: e.order ?? 100,
      alwaysOn: e.constant === true,
      caseSensitive: e.case_sensitive === true,
      enabled: e.disable !== true,
    };
  });
}

/** Mirrors `worldInfoToEntries`: builds a World Info JSON object from a
 * list of lore entries, suitable for `JSON.stringify` + writing to disk.
 * Entry keys in the `entries` map are stable stringified indices — order
 * is preserved by the caller's array order. */
export function entriesToWorldInfo(entries: LoreEntryFields[]): WorldInfoFile {
  const result: Record<string, WorldInfoEntryJson> = {};
  entries.forEach((entry, index) => {
    result[String(index)] = {
      key: entry.keys,
      keysecondary: entry.secondaryKeys,
      content: entry.content,
      comment: entry.comment,
      constant: entry.alwaysOn,
      order: entry.priority,
      disable: !entry.enabled,
      case_sensitive: entry.caseSensitive,
    };
  });
  return { entries: result };
}

export function stringifyWorldInfo(entries: LoreEntryFields[]): string {
  return JSON.stringify(entriesToWorldInfo(entries), null, 2);
}

